const body = $input.first().json;
const msg = body?.entry?.[0]?.changes?.[0]?.value?.messages?.[0];
if (!msg) return [];
return [{ json: { from: msg.from, text: msg.text?.body || '', type: msg.type, waId: msg.id } }];

const text = $node['Extract Message'].json.text.toLowerCase();
let score = 0;
let redirect = 'direct';

// Budget detection
const budgetMatch = text.match(/(\d+)[k\s]*euros?|€\s*(\d+)/i);
if (budgetMatch) {
  const budget = parseInt(budgetMatch[1] || budgetMatch[2]) * (text.includes('k') ? 1000 : 1);
  if (budget >= 80000 && budget <= 350000) { score += 30; redirect = 'exp'; }
  else if (budget > 350000) { score += 22; redirect = 'personal'; }
}

// Zone detection
const zones = ['madrid','barcelona','marbella','costa del sol','valencia','alicante'];
if (zones.some(z => text.includes(z))) score += 25;

// Intent detection
if (text.match(/invert|roi|rentab|beneficio/)) { score += 25; }
if (text.match(/comprar|compra|piso|casa|apartamento/)) score += 15;

return [{ json: { ...$input.first().json, score, redirect } }];
